def get_ludic(n):
    """
    Generate all lucid numbers <= n.
    A lucid number is the product of two non-unit non-zero integers a and b
    such that the sum of digits of a is less than or equal to the sum of digits of b.
    """
    lucid_numbers = []

    def get_sum_of_digits(num):
