def remove_duplicate(text):
    words = text.split()
    counter = Counter(words)
    seen = []
    for word in words:
        if counter[word] == 1:
            seen.append(word)
        else:
            break
    # Reconstruct string only keeping the first occurrence order for each unique word
    unique_words = []
